section.code:
{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "https://faion.net/schemas/aws-infra-llm-prompts.json",
  "type": "object",
  "required": [
    "artefact_id",
    "prompt_intent",
    "context_elicitation_present",
    "output_schema_declared",
    "constraints_pinned",
    "compliance_claim_check",
    "provider_key_scope",
    "owner"
  ],
  "properties": {
    "artefact_id": {
      "type": "string",
      "description": "stable prompt id"
    },
    "prompt_intent": {
      "type": "string",
      "description": "enum: design | review | iam-policy | dr-runbook | migration-plan"
    },
    "context_elicitation_present": {
      "type": "boolean",
      "description": "true (workload shape + latency + region + compliance + budget all present)"
    },
    "output_schema_declared": {
      "type": "boolean",
      "description": "true"
    },
    "constraints_pinned": {
      "type": "boolean",
      "description": "true"
    },
    "compliance_claim_check": {
      "type": "boolean",
      "description": "true (no certification claims in prompt or expected output)"
    },
    "provider_key_scope": {
      "type": "string",
      "description": "enum: project-specific | shared (project-specific required)"
    },
    "owner": {
      "type": "string",
      "description": "single named handle"
    }
  }
}
